import Layout from '../components/Layout';

export default function Error({ statusCode }) {
  return (
    <Layout>
      <div className="flex flex-col items-center justify-center min-h-[300px]">
        <h1 className="text-3xl font-extrabold mb-4">{statusCode ? `Error ${statusCode}` : 'An error occurred'}</h1>
        <p className="text-lg text-gray-700 mb-2">Sorry, something went wrong.</p>
        <a href="/" className="text-blue-700 underline focus:outline-none focus:ring-2 focus:ring-blue-600">Go back home</a>
      </div>
    </Layout>
  );
}

Error.getInitialProps = ({ res, err }) => {
  const statusCode = res ? res.statusCode : err ? err.statusCode : 404;
  return { statusCode };
};
